    <script>
    const triggerQuickReply = text => {
        if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
        if (typeof triggerSlash === 'function') {
          triggerSlash(`/send ${text}|/trigger`);
        } else {
          console.log('SillyTavern environment not detected. Would send:', text);
        }
    };

    const sendToChatBox = text => {
        if (!text || text.trim().length === 0) return;

        try {
            const $textarea = $(parent.document).find('#send_textarea');

            if ($textarea.length === 0) {
                console.error('未找到聊天输入框 (#send_textarea)。回退到直接发送。');
                triggerQuickReply(text);
                return;
            }

            const currentContent = $textarea.val() || '';

            const separator = currentContent.trim() ? '\n' : '';
            const newContent = currentContent + separator + text.trim();

            $textarea.val(newContent);
            $textarea.trigger('input').focus();

            console.log('已添加文本到聊天框:', text.trim());
        } catch (error) {
            console.error('发送到聊天框时出错。请检查 jQuery 是否可用:', error);
            triggerQuickReply(text);
        }
    };

    document.addEventListener('DOMContentLoaded', () => {
        initThemeToggle();
        const renderer = new OptionsRenderer('options-data-source');
        renderer.init();
    });

    function initThemeToggle() {
        const body = document.body;
        const buttons = document.querySelectorAll('.theme-btn');
        const savedTheme = localStorage.getItem('optionsTheme') || 'night';

        const switchToTheme = (theme) => {
            body.classList.toggle('day-mode', theme === 'day');
            buttons.forEach(btn => btn.classList.toggle('active', btn.dataset.theme === theme));
            localStorage.setItem('optionsTheme', theme);
        };

        buttons.forEach(btn => btn.addEventListener('click', () => switchToTheme(btn.dataset.theme)));
        switchToTheme(savedTheme);
    }

    class OptionsRenderer {
        constructor(dataSourceId) {
            this.dataSourceId = dataSourceId;
            this.optionsData = '';
            this.optionsList = document.getElementById('options-list');
        }

        init() {
            try {
                const scriptEl = document.getElementById(this.dataSourceId);
                this.optionsData = scriptEl.textContent.trim();
                this.renderOptions();
            } catch (error) {
                console.error('Render error:', error);
                document.body.innerHTML = `<div class="text-red-500 p-4">Error: ${error.message}</div>`;
            }
        }

        handleOptionClick(button, optionText) {
            sendToChatBox(optionText);

            button.classList.add('selected-multi');
            button.style.transform = 'translateY(0)';
            setTimeout(() => { 
                button.classList.remove('selected-multi');
            }, 300);
        }

        renderOptions() {
            this.optionsList.innerHTML = '';
            const optionRegex = /\[Opt(\d+):\s*([^\]]+)\]\s*(.+)/g; 
            let match;
            let foundCount = 0;

            while ((match = optionRegex.exec(this.optionsData)) !== null && foundCount < 10) {
                const optionNumber = parseInt(match[1]);
                const optionDesc = match[2].trim();
                const cleanOption = match[3].trim();

                const li = document.createElement('li');
                li.className = 'theme-transition';

                li.innerHTML = `
                    <button class="option-btn w-full text-left text-gray-300 border-gray-700/30 flex items-center justify-between" data-option="${cleanOption}">
                        <div class="option-content">
                            <div class="option-icon">${optionNumber}</div>
                            <div class="option-text">
                                <div class="option-prefix">${optionDesc}</div>
                                <div class="option-main text-gray-300">${cleanOption}</div>
                            </div>
                        </div>
                        <i class="fa fa-arrow-down ml-2 text-primary/50 flex-shrink-0"></i>
                    </button>
                `;

                const button = li.querySelector('button');
                button.addEventListener('click', (e) => {
                    e.preventDefault();
                    this.handleOptionClick(button, cleanOption);
                });

                this.optionsList.appendChild(li);
                foundCount++;
            }

            if (foundCount === 0) {
                this.optionsList.innerHTML = '<li class="text-gray-500 p-4 text-center">选项数据缺失...</li>';
            }
        }
    }
