        <div id="output-area">
            <label>Kết quả tạo (Result)</label>
            <textarea id="result" readonly></textarea>
            <button class="copy-btn" onclick="copyResult()">📋 Sao chép vào bộ nhớ tạm</button>
        </div>
    </div>

    <script>
        const chapters = [
            "Chương 1: Bora Bầu Trời Đỏ",
            "Chương 2: Giải cứu Macao",
            "Chương 3: Biệt thự Everlue",
            "Chương 4: Eisenwald",
            "Chương 5: Đảo Galuna",
            "Chương 6: Phantom Lord",
            "Chương 7: Loke Tinh Linh",
            "Chương 8: Tháp Thiên Đường",
            "Chương 9: Nội chiến Hội",
            "Chương 10: Oracion Seis",
            "Chương 11: Edolas (Thượng)",
            "Chương 12: Edolas (Hạ)",
            "Chương 13: Sóng gió hậu chiến",
            "Chương 14: Nàng Tiên Phượng Hoàng",
            "Chương 15: Đảo Tenrou (Thượng)",
            "Chương 16: Đảo Tenrou (Hạ)",
            "Chương 17: Bảy năm trống rỗng",
            "Chương 18: Đại Hội Ma Thuật",
        ];

        let currentChapter = chapters[0];

        // Khởi tạo
        window.onload = function() {
            const cContainer = document.getElementById('chapter-container');
            chapters.forEach((c, idx) => {
                let btn = document.createElement('div');
                btn.className = idx === 0 ? 'chapter-btn active' : 'chapter-btn';
                btn.innerText = c;
                btn.onclick = () => {
                    currentChapter = c;
                    document.querySelectorAll('.chapter-btn').forEach(b => b.classList.remove('active'));
                    btn.classList.add('active');
                };
                cContainer.appendChild(btn);
            });

            // Điền sẵn một ví dụ khả năng
            addAbility("Phỉ Thúy Nhãn", "Ma nhãn bẩm sinh. Mắt trái có thể nhìn thấy dòng chảy của các nguyên tố ma lực trong khí quyển; mắt phải có thể nhìn thấu trạng thái chi tiết, khả năng đặc biệt, điểm yếu và cả chân danh khắc sâu trong linh hồn của sinh vật.");
            // Điền sẵn một ví dụ ma thuật
            addMagicExample();
        };

        function addAbility(name = "", desc = "") {
            const div = document.createElement('div');
            div.className = 'dynamic-card';
            div.style.background = 'rgba(255,255,255,0.05)';
            div.innerHTML = `
            <div class="grid-box" style="grid-template-columns: 1fr 2fr;">
                <input type="text" placeholder="Tên khả năng" class="ab-name" value="${name}">
                <input type="text" placeholder="Mô tả khả năng" class="ab-desc" value="${desc}">
            </div>
            <button class="btn-small" onclick="this.parentElement.remove()">Xóa mục</button>
        `;
            document.getElementById('ability-list').appendChild(div);
        }

        function addMagic() {
            const id = Date.now();
            const div = document.createElement('div');
            div.className = 'dynamic-card';
            div.innerHTML = `
            <div class="grid-box">
                <input type="text" placeholder="Tên ma thuật (VD: Hỏa Sát Long Ma Thuật)" class="mg-name">
                <select class="mg-stage">
                    <option value="Sơ cấp">Sơ cấp</option>
                    <option value="Thành thạo">Thành thạo</option>
                    <option value="Bậc thầy">Bậc thầy</option>
                </select>
            </div>
            <input type="text" placeholder="Nguyên lý ma thuật/Mô tả hiệu quả" class="mg-desc" style="margin-top:10px;">

            <div class="moves-container">
                <label style="font-size:0.8rem; color:#aaa;">Danh sách chiêu thức / Bí kỹ:</label>
                <div class="moves-list" id="moves-${id}"></div>
                <button class="btn-small" style="color:var(--gold-primary); border-color:var(--gold-primary);" onclick="addMove('moves-${id}')">+ Thêm chiêu thức</button>
            </div>

            <button class="btn-small" style="position:absolute; top:10px; right:10px;" onclick="this.parentElement.remove()">Gỡ bỏ ma thuật</button>
        `;
            document.getElementById('magic-list').appendChild(div);
        }

        function addMagicExample() {
            const id = Date.now();
            const div = document.createElement('div');
            div.className = 'dynamic-card';
            div.innerHTML = `
            <div class="grid-box">
                <input type="text" value="Hỏa Sát Long Ma Thuật" class="mg-name">
                <select class="mg-stage">
                    <option value="Bậc thầy" selected>Bậc thầy</option>
                    <option value="Thành thạo">Thành thạo</option>
                    <option value="Sơ cấp">Sơ cấp</option>
                </select>
            </div>
            <input type="text" value="Chuyển đổi thể chất thành rồng, ma thuật cổ đại dùng để diệt rồng. Có thể ăn lửa để hồi phục thể lực." class="mg-desc" style="margin-top:10px;">

            <div class="moves-container">
                <label style="font-size:0.8rem; color:#aaa;">Danh sách chiêu thức / Bí kỹ:</label>
                <div class="moves-list" id="moves-${id}">
                    <div class="move-item">
                        <input type="text" placeholder="Tên chiêu" value="Tiếng gầm của Hỏa Long">
                        <input type="text" placeholder="Hiệu quả" value="Phun ra một hơi thở lửa khổng lồ từ miệng.">
                        <button class="btn-small" onclick="this.parentElement.remove()">X</button>
                    </div>
                </div>
                <button class="btn-small" style="color:var(--gold-primary); border-color:var(--gold-primary);" onclick="addMove('moves-${id}')">+ Thêm chiêu thức</button>
            </div>
            <button class="btn-small" style="position:absolute; top:10px; right:10px;" onclick="this.parentElement.remove()">Gỡ bỏ ma thuật</button>
        `;
            document.getElementById('magic-list').appendChild(div);
        }

        function addMove(listId) {
            const div = document.createElement('div');
            div.className = 'move-item';
            div.innerHTML = `
            <input type="text" placeholder="Tên chiêu">
            <input type="text" placeholder="Hiệu quả">
            <button class="btn-small" onclick="this.parentElement.remove()">X</button>
        `;
            document.getElementById(listId).appendChild(div);
        }

        function generate() {
            const name = document.getElementById('charName').value;
            const gender = document.getElementById('charGender').value;
            const age = document.getElementById('charAge').value;
            const race = document.getElementById('charRace').value;
            const guild = document.getElementById('charGuild').value;
            const rank = document.getElementById('charRank').value;
            const look = document.getElementById('charLook').value;
            const pers = document.getElementById('charPers').value;
            const bg = document.getElementById('charBg').value;
            const open = document.getElementById('charOpening').value;

            // Thu thập khả năng
            let abs = [];
            document.querySelectorAll('#ability-list .dynamic-card').forEach(card => {
                const n = card.querySelector('.ab-name').value;
                const d = card.querySelector('.ab-desc').value;
                if (n) abs.push(`- 【${n}】: ${d}`);
            });

            // Thu thập ma thuật
            let magics = [];
            document.querySelectorAll('#magic-list .dynamic-card').forEach(card => {
                const mName = card.querySelector('.mg-name').value;
                const mStage = card.querySelector('.mg-stage').value;
                const mDesc = card.querySelector('.mg-desc').value;

                if (mName) {
                    let moves = [];
                    card.querySelectorAll('.move-item').forEach(mv => {
                        const inputs = mv.querySelectorAll('input');
                        if (inputs[0].value) moves.push(`  * [${inputs[0].value}]: ${inputs[1].value}`);
                    });

                    magics.push(`### 🔮 ${mName} [${mStage}]\n> Nguyên lý: ${mDesc}\n${moves.join('\n')}`);
                }
            });

            const finalTxt = `
👆 ĐƠN ĐĂNG KÝ THÀNH VIÊN HỘI FAIRY TAIL 👇
━━━━━━━━━━━━━━━━━━━━━━━━━━
【THÔNG TIN CƠ BẢN】
◈ Họ tên: ${name}
◈ Giới tính: ${gender} | Tuổi: ${age}
◈ Chủng tộc: ${race}
◈ Hội quán: ${guild} 👆
◈ Cấp bậc: ${rank}

【PHÁC HỌA NHÂN VẬT】
👁 Ngoại hình: ${look}
🧠 Tính cách: ${pers}

━━━━━━━━━━━━━━━━━━━━━━━━━━
【KHẢ NĂNG ĐẶC BIỆT】
${abs.length ? abs.join('\n') : "(Không có thể chất đặc biệt)"}

【HỒ SƠ MA THUẬT】
${magics.length ? magics.join('\n\n') : "(Chưa có ghi chép ma thuật, hãy mau đi học!)"}

━━━━━━━━━━━━━━━━━━━━━━━━━━
【BỐI CẢNH HUYỀN THOẠI】
📜 ${bg}

【LỊCH SỬ XUẤT HIỆN】
Chương hiện tại: 《${currentChapter}》
💬 Lời thoại mở đầu:
“${open}”
━━━━━━━━━━━━━━━━━━━━━━━━━━
(Được tạo bởi Fairy Tail Guild Archives)
`;

            const resArea = document.getElementById('output-area');
            resArea.style.display = 'block';
            document.getElementById('result').value = finalTxt;
            resArea.scrollIntoView({
                behavior: 'smooth'
            });
        }

        function copyResult() {
            const copyText = document.getElementById("result");
            copyText.select();
            copyText.setSelectionRange(0, 99999);
            navigator.clipboard.writeText(copyText.value).then(() => {
                alert("✅ Thẻ nhân vật đã được sao chép! Hãy mau đến sảnh Hội báo danh đi!");
            });
        }
    </script>
</body>
</html>
